#include<bits/stdc++.h>
using namespace std;
char tr[1005];
int n,len;
string s;
void dfs(int k)
{
    if(2*k<=len) dfs(2*k);
    if(2*k+1<=len) dfs(2*k+1);
    cout<<tr[k];
}
int main()
{
    cin>>n>>s;
    len=pow(2,n+1)-1;
    int k=0;
    for(int i=len-s.size()+1;i<=len;i++)
    {
        if(s[k]=='1') tr[i]='I';
        else tr[i]='B';
        k++;
    }
    for(int i=len;i>=1;i=i-2)
    {
        if(tr[i]=='I'&&tr[i-1]=='I') tr[i/2]='I';
        else if(tr[i]=='B'&&tr[i-1]=='B') tr[i/2]='B';
        else tr[i/2]='F';
    }
    dfs(1);
    return 0;
}
